UPDATE payments
   SET payment_key = #{paymentKey}
     , method = #{method}
     , status = #{status}
     , paid_at = #{paidAt}
 WHERE id = #{id}

UPDATE payments
   SET status = 'FAILED'
 WHERE id = #{id}

UPDATE payments
   SET status = #{status}
     , canceled_at = #{canceledAt}
     , cancel_reason = #{cancelReason}
 WHERE id = #{id}
